mapper.update:
update TB_WORK_ORDER_PROC
set  use_qty = #{useQty}
    ,upd_id   = #{userId}
    ,upd_dt  = getdate()
where work_proc_id = #{workProcId}

update TB_WORK_ORDER_PROC
set    prod_qty     = #{prodQty}
      ,prod_yield   = #{prodYield}
      ,upd_id       = #{userId}
